SELECT id, record_id, coupon_id, user_id, order_id, usage_type, 
       usage_time, remark, create_time
FROM coupon_usage_record
WHERE coupon_id = #{couponId}
  AND order_id = #{orderId}

SELECT id, record_id, coupon_id, user_id, order_id, usage_type, 
       usage_time, remark, create_time
FROM coupon_usage_record
WHERE coupon_id = #{couponId}
  AND order_id = #{orderId}
  AND usage_type = 'VERIFY'

SELECT id, record_id, coupon_id, user_id, order_id, usage_type, 
       usage_time, remark, create_time
FROM coupon_usage_record
WHERE coupon_id = #{couponId}
  AND order_id = #{orderId}
  AND usage_type = 'ROLLBACK'
